import json


def parse_json(json_string):
    '''
    Parse json_string and return the data as a Python dictionary
    This helps you work with data from APIs or config files easily
    '''
    try:
        return json.loads(json_string)
    except json.JSONDecodeError as e:
        print(f"Oops! The JSON data has an error: {e}")
        return None

