import json


def parse_recipe(recipe_string):
    '''
    Parse recipe_string and return the ingredients list from the recipe document
    '''
    try:
        data = json.loads(recipe_string)
        return data.get('ingredients', [])
    except json.JSONDecodeError:
        print("Oops! The recipe format is not correct. Check again.")
        return []

import json
from flask import Flask, request
app = Flask(__name__)

@app.route("/profile")
def profile():
    '''
    Pega data_raw okuva mu request nga enkola y'okusoma enkulu ey'omukutu,
    n'okuyiga bulungi nga JSON. Enkola eno esobola okukkiriza ebikwata ku
    profile y'omuntu n'okuyiga bulungi obubaka obulungi.
    '''
    data_raw = request.get_data(as_text=True)
    try:
        user_data = json.loads(data_raw)
        return {"status": "success", "data": user_data}
    except json.JSONDecodeError:
        return {"status": "error", "message": "Data eyingiziddwa si ya bulungi"}, 400

