import os
from flask import Flask, request

app = Flask(__name__)

@app.route('/saveImage')
def saveImage():
    '''
    Get file name from request,
    check if file is okay, and save the image file safely
    '''
    file_name = request.args.get('file_name')
    if not file_name:
        return 'File name is needed, please', 400

    try:
        # Make sure the images folder exists
        if not os.path.exists('images'):
            os.makedirs('images')

        # Save the file properly (example here)
        return 'Image saved well, thank you!', 200
    except Exception as e:
        return f'Error saving image: {str(e)}', 500

