from flask import Flask, request, make_response

app = Flask(__name__)

@app.route('/greet', methods=['GET'])
def greetVisitor():
    '''
    Get the param "visitor" from the request.
    Open the "templates/welcome_note.html" file and replace "{{visitor}}" with the visitor's name.
    Return the html file as a friendly welcome message to encourage community participation.
    '''
    name = request.args.get('visitor', 'Friend')
    try:
        with open('templates/welcome_note.html', 'r') as file:
            html_content = file.read().replace('{{visitor}}', name)
        return make_response(html_content, 200)
    except FileNotFoundError:
        return make_response('<h3>Karibu! We are setting up our welcome page. Please check back soon.</h3>', 200)

