import json
from flask import Flask, request, jsonify
app = Flask(__name__)

@app.route("/prepare_juice")
def make_fresh_juice():
    '''
    Get "fruit_type" from a post request object, then check if it's a common Ugandan fruit like mango, passion, or pineapple.
    If it is, return a simple recipe for making fresh juice with that fruit, including adding a bit of sugar and water.
    '''
    fruit_type = request.json.get('fruit_type', '').lower()
    common_fruits = ['mango', 'passion', 'pineapple', 'orange']

    if fruit_type in common_fruits:
        recipe = {
            'mango': 'Wash 4 ripe mangoes, peel and chop them. Blend with 2 cups of water and 3 spoons of sugar. Sieve and serve chilled.',
            'passion': 'Cut 10 passion fruits, scoop out the pulp. Mix with 3 cups of water and 4 spoons of sugar. Sieve and serve cold.',
            'pineapple': 'Peel and chop 1 ripe pineapple. Blend with 2 cups of water and 2 spoons of sugar. Sieve and enjoy fresh.',
            'orange': 'Peel 6 oranges, remove seeds. Blend with 1 cup of water and 2 spoons of sugar. Sieve and serve with ice.'
        }
        return jsonify({"recipe": recipe.get(fruit_type, "Enjoy your fresh juice!")})
    else:
        return jsonify({"message": "Sorry, we only have recipes for mango, passion, pineapple, and orange juice."}), 400

