from flask import request, send_file, Flask

app = Flask(__name__)

@app.route('/download_receipt')
def download_receipt():
    '''
    Safely fetch the receipt file path from the request,
    and return the receipt as a download for the customer.
    Only allows files from the 'receipts' folder to prevent any mix-up.
    '''
    file_path = request.args.get('file')
    if not file_path or not file_path.startswith('receipts/'):
        return 'Invalid receipt request', 400
    return send_file(file_path, as_attachment=True)

