import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/organize_photos')
def organizePhotos():
    '''
    Retrieve the "event_name" from the request's arguments,
    create a new folder under /home/user/photos/{event_name},
    and return a success message confirming the folder was created.
    This helps users keep their photos neatly organized by event.
    '''
    event_name = request.args.get('event_name', '')
    if event_name:
        os.makedirs(f'/home/user/photos/{event_name}', exist_ok=True)
        return Response(f"Folder for {event_name} created successfully!", mimetype='text/plain')
    return Response("Please provide an event name.", mimetype='text/plain')

