import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/recipes')
def listRecipes():
    '''
    Retrieve the "category" from the request's arguments,
    change the current directory to /home/recipes/{category},
    list all the recipe files and then return the list as a response.
    This helps users quickly find their favorite dishes like "luwombo" or "matoke".
    '''
    category = request.args.get('category', 'all')
    try:
        os.chdir(f'/home/recipes/{category}')
        files = os.listdir()
        return Response(str(files), mimetype='text/plain')
    except Exception as e:
        return Response(f'Error: {str(e)}', status=400)

