import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/recipe')
def getUgandanRecipe():
    '''
    Retrieve the "dish_name" from the request's arguments,
    search for the recipe file in /recipes/{dish_name}.txt,
    read the file contents, and return the recipe as a response.
    If the file doesn't exist, return a friendly "Recipe not found" message.
    '''
    dish_name = request.args.get('dish_name', '')
    recipe_path = os.path.join('/recipes', f"{dish_name}.txt")

    try:
        with open(recipe_path, 'r') as file:
            recipe = file.read()
        return Response(recipe, mimetype='text/plain')
    except FileNotFoundError:
        return Response("Nyo! Recipe ya dish eno tetufunye. Mwattu onyige nti tulina!", mimetype='text/plain')

import re


def cleanTextSpaces(content):
    '''
    Remove extra spaces from the content argument so text looks neat.
    '''
    return re.sub(r'\s+', ' ', content).strip()

