    ingredients = {
        'rolex': ['chapati', 'eggs', 'onions', 'tomatoes', 'salt', 'oil'],
        'katogo': ['matooke', 'beef', 'onions', 'tomatoes', 'oil']
    }
    return ingredients.get(dish_name, [])


