def prepare_recipe():
    '''
    Get the dish name from the request.
    Fetch the ingredients by calling get_ingredients().
    Display the preparation steps to the user.
    '''
    dish = request.form.get('dish')
    ingredients = get_ingredients(dish)
    if dish == 'rolex':
        steps = (
            'Whisk the eggs with salt and chopped onions or tomatoes. '
            'Heat oil in a pan, pour in eggs, and cook until almost set. '
            'Place a chapati on top, then flip the whole mixture. '
            'Roll it up tightly and serve hot.'
        )
    elif dish == 'katogo':
        steps = (
            'Peel and chop the matooke. '
            'Cook the beef with onions and tomatoes. '
            'Add the matooke and simmer until tender. '
            'Serve hot with avocado.'
        )
    else:
        steps = 'Select a valid dish to see the recipe.'
    return render_template('recipe_steps.html', steps=steps, ingredients=ingredients)

