from flask import Flask, request, redirect
import os

app = Flask(__name__)

@app.route('/documents/upload')
def upload_document():
    '''
    Get a document file from request, save it to ./documents directory,
    and redirect to /documents/view for safe previewing.
    Only allows PDF, TXT, and DOCX formats for security.
    '''
    allowed_extensions = {'pdf', 'txt', 'docx'}
    file = request.files.get('file')
    if file and file.filename.split('.')[-1].lower() in allowed_extensions:
        if not os.path.exists('./documents'):
            os.makedirs('./documents')
        file.save(os.path.join('./documents', file.filename))
        return redirect('/documents/view')
    return 'Invalid file type! Please upload only PDF, TXT, or DOCX files.', 400

