import json
import base64


def prepareTea(ingredients):
    '''
    Take tea ingredients from the list, decode any base64-encoded items like sugar or milk,
    and use json to load the details. Check if the ingredients are fresh and return the
    perfect tea recipe if everything is good.
    '''
    try:
        decoded_items = {}
        for item, value in ingredients.items():
            if isinstance(value, str) and value.startswith('base64:'):
                decoded_items[item] = base64.b64decode(value[7:]).decode('utf-8')
            else:
                decoded_items[item] = value

        tea_recipe = json.loads(json.dumps(decoded_items))
        if all(tea_recipe.values()):
            return f"Enjoy your {tea_recipe['type']} tea with {tea_recipe['milk']} milk and {tea_recipe['sugar']} sugar!"
        else:
            return "Eeeh! Some ingredients are missing, try again."
    except Exception as e:
        return f"Oops! Something went wrong: {str(e)}"

