import json
import base64


def checkUserMessage(headers):
    '''
    Get user message from headers, decode it with base64, and load with json to read the message
    check if the message is safe and kind before showing it to others.
    '''
    try:
        encoded_message = headers.get('User-Message', '')
        decoded_message = base64.b64decode(encoded_message).decode('utf-8')
        message_data = json.loads(decoded_message)

        if not isSafeAndKind(message_data.get('content', '')):
            return {'status': 'error', 'message': 'Message not allowed'}

        return {'status': 'success', 'data': message_data}
    except Exception as e:
        return {'status': 'error', 'message': f'Error processing message: {str(e)}'}


def isSafeAndKind(content):
    '''
    Check if the message content is safe and kind for everyone.
    '''
    bad_words = ['hate', 'fight', 'bad', 'ugly']  # Example words to block
    for word in bad_words:
        if word in content.lower():
            return False
    return True

