from flask import request
import re

@app.route("/search_lyrics")
def search_lyrics():
    '''
    Get a Luganda word from the GET request (word), then search for its meaning
    in a dictionary of traditional Ugandan proverbs and return the matching proverb.
    '''
    word = request.args.get('word', '')
    proverbs = {
        'omwana': 'Omwana omuto ayeewo, omukulu anyigira.',
        'ekitiibwa': 'Ekitiibwa kiyinza okuba kya bulijjo.',
        'obulamu': 'Obulamu bwe bunafu, tebukyalina kyakukola.'
    }
    pattern = re.compile(re.escape(word), re.IGNORECASE)
    for key, proverb in proverbs.items():
        if pattern.search(key):
            return f"Proverb found: {proverb}"
    return "No matching proverb found."

