import hashlib


def calculateChecksum(filePath):
    '''
    Enkuluzi eno esobola okukola checksum ya fayiro nga ebaddewo mu kompyuta,
    okusobola okukebera obulungi oba okukebera oba fayiro eno teyagweddeko.
    '''
    try:
        with open(filePath, 'rb') as f:
            fileData = f.read()
            return hashlib.sha256(fileData).hexdigest()
    except FileNotFoundError:
        print("Fayiro tekuli! Nno nno.")

